messages.content:
Please evaluate if this ticket is complete:

**Ticket ID:** {{ item().id }}
**Summary:** {{ item().summary }}
**Initial Description:** {{ item().initialDescription | d('No description provided') }}

**10 Most Recent Notes (newest first):**
{% for note in (item().notes | d([]))[:10] %}
---
**Date:** {{ note._info.dateEntered | d(note.dateCreated | d('Unknown date')) }}
**Author:** {{ note.member.name | d(note.createdBy | d('Unknown')) }}
**Text:** {{ note.text | d('No text') }}
{% endfor %}

publish.value:
{%- set results = [] -%}
{%- for i in range(CTX.completed_tickets | length) -%}
{%- set ticket = CTX.completed_tickets[i] -%}
{%- set ai_response = CTX.ai_evaluation[i].result.result.choices[0].message.content | from_json_string -%}
{%- set _ = results.append({'ticket': ticket, 'ai_result': ai_response}) -%}
{%- endfor -%}
{{ results }}

{% set two_weeks_ago = now() | convert_from_epoch | datedelta(weeks=-2) %}
{% set stale = [] %}
{% for ticket in CTX.completed_tickets %}
{% set last_updated = ticket._info.lastUpdated | parse_datetime(ignoretz=true) %}
{% if last_updated < two_weeks_ago %}
{% set _ = stale.append(ticket) %}
{% endif %}
{% endfor %}
{{ stale }}

